# Salesforce Integration
class SalesforceClient:
    def __init__(self, instance_url, access_token):
        self.instance_url = instance_url
        self.headers = {
            'Authorization': f'Bearer {access_token}',
            'Content-Type': 'application/json'
        }

    def create_lead(self, lead_data):
        """Create a new lead in Salesforce"""
        url = f"{self.instance_url}/services/data/v57.0/sobjects/Lead"
        response = requests.post(url, headers=self.headers, json={
            'FirstName': lead_data['first_name'],
            'LastName': lead_data['last_name'],
            'Email': lead_data['email'],
            'Company': lead_data['company'],
            'LeadSource': 'Web'
        })
        return response.json()

# HubSpot Integration
class HubSpotClient:
    def __init__(self, api_key):
        self.api_key = api_key
        self.base_url = 'https://api.hubapi.com'

    def create_contact(self, contact_data):
        """Create a contact in HubSpot"""
        url = f"{self.base_url}/crm/v3/objects/contacts"
        response = requests.post(url,
            headers={'Authorization': f'Bearer {self.api_key}'},
            json={
                'properties': {
                    'email': contact_data['email'],
                    'firstname': contact_data['first_name'],
                    'lastname': contact_data['last_name']
                }
            }
        )
        return response.json()

# Stripe Integration for Payments
import stripe

stripe.api_key = 'sk_test_your_key'

def create_subscription(customer_email, price_id):
    """Create a subscription in Stripe"""
    # Create or get customer
    customers = stripe.Customer.list(email=customer_email, limit=1)
    if customers.data:
        customer = customers.data[0]
    else:
        customer = stripe.Customer.create(email=customer_email)

    # Create subscription
    subscription = stripe.Subscription.create(
        customer=customer.id,
        items=[{'price': price_id}],
        payment_behavior='default_incomplete',
        expand=['latest_invoice.payment_intent']
    )

    return {
        'subscription_id': subscription.id,
        'client_secret': subscription.latest_invoice.payment_intent.client_secret
    }

