const express = require('express');
const crypto = require('crypto');

const app = express();

// Stripe Webhook Handler
app.post('/webhooks/stripe', express.raw({ type: 'application/json' }), (req, res) => {
    const sig = req.headers['stripe-signature'];
    const endpointSecret = process.env.STRIPE_WEBHOOK_SECRET;

    let event;
    try {
        event = stripe.webhooks.constructEvent(req.body, sig, endpointSecret);
    } catch (err) {
        return res.status(400).send(`Webhook Error: ${err.message}`);
    }

    switch (event.type) {
        case 'customer.subscription.created':
            handleNewSubscription(event.data.object);
            break;
        case 'customer.subscription.deleted':
            handleCancelledSubscription(event.data.object);
            break;
        case 'invoice.payment_succeeded':
            handleSuccessfulPayment(event.data.object);
            break;
    }

    res.json({ received: true });
});

// GitHub Webhook Handler
app.post('/webhooks/github', express.json(), (req, res) => {
    const signature = req.headers['x-hub-signature-256'];
    const payload = JSON.stringify(req.body);
    const secret = process.env.GITHUB_WEBHOOK_SECRET;

    const expectedSig = 'sha256=' + crypto
        .createHmac('sha256', secret)
        .update(payload)
        .digest('hex');

    if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSig))) {
        return res.status(401).send('Invalid signature');
    }

    const event = req.headers['x-github-event'];

    switch (event) {
        case 'push':
            handlePushEvent(req.body);
            break;
        case 'pull_request':
            handlePREvent(req.body);
            break;
        case 'issues':
            handleIssueEvent(req.body);
            break;
    }

    res.status(200).send('OK');
});

